Code.Terraform:
```hcl
# Terraform - 为 AppSync API 启用字段级日志记录
resource "aws_appsync_graphql_api" "<example_resource_name>" {
  name                = "<example_resource_name>"
  authentication_type = "AWS_IAM"

  log_config {
    cloudwatch_logs_role_arn = "<cloudwatch_logs_role_arn>" # 关键：允许记录到 CloudWatch
    field_log_level          = "ERROR"                        # 关键：合规的字段级日志记录
  }
}
```
